{"file_path": "/project/legacy/ui/legacy/src/test/java/com/fsck/k9/view/UserInputEmailAddressParserInvalidAddressTest.kt", "content": "package com.fsck.k9.view

import assertk.assertFailure
import assertk.assertions.isInstanceOf
import kotlin.test.Test

class UserInputEmailAddressParserInvalidAddressTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `address with slash at end should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("test@gmail.com/")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with slash in domain should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("test@gmai/l.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with invalid character in domain should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("test@gmail.com#")
        }.isInstanceOf<InvalidEmailAddressException>()
    }

    @Test
    fun `address with slash in local part is valid`() {
        // Note: According to RFC 5321, slash is allowed in the local part
        val addresses = parser.parse("test/user@gmail.com")
        assertk.assertThat(addresses).assertk.assertions.isNotEmpty()
    }

    @Test
    fun `address with space in domain should throw InvalidEmailAddressException`() {
        assertFailure {
            parser.parse("test@gmai l.com")
        }.isInstanceOf<InvalidEmailAddressException>()
    }
}
"}

