 16→/**
 17→ * Parse an email address.
 18→ *
 19→ * This class currently doesn't support internationalized domain names (RFC 5891) or non-ASCII local parts (RFC 6532).
 20→ *
 21→ * From RFC 5321:
 22→ * ```
 23→ * Mailbox                 = Local-part "@" ( Domain / address-literal )
 24→ *
 25→ * Local-part              = Dot-string / Quoted-string
 26→ * Dot-string              = Atom *("."  Atom)
 27→ * Quoted-string           = DQUOTE *QcontentSMTP DQUOTE
 28→ * QcontentSMTP            = qtextSMTP / quoted-pairSMTP
 29→ * qtextSMTP               = %d32-33 / %d35-91 / %d93-126
 30→ * quoted-pairSMTP         = %d92 %d32-126
 31→ *
 32→ * Domain                  - see DomainParser
 33→ * address-literal         - We intentionally don't support address literals
 34→ * ```
 35→ */
 36→internal class EmailAddressParser(
 37→    input: String,
 38→    private val config: EmailAddressParserConfig,
 39→) : AbstractParser(input) {
 40→
 41→    fun parse(): EmailAddress {
 42→        val emailAddress = readEmailAddress()
 43→
 44→        if (!endReached()) {
 45→            parserError(ExpectedEndOfInput)
 46→        }
 47→
 48→        if (
 49→            config.isEmailAddressLengthCheckEnabled && Warning.EmailAddressExceedsLengthLimit in emailAddress.warnings
 50→        ) {
 51→            parserError(TotalLengthExceeded)
 52→        }
 53→
 54→        if (config.isLocalPartLengthCheckEnabled && Warning.LocalPartExceedsLengthLimit in emailAddress.warnings) {
 55→            parserError(LocalPartLengthExceeded, position = input.lastIndexOf('@'))
 56→        }
 57→
 58→        if (
 59→            !config.isLocalPartRequiringQuotedStringAllowed && Warning.QuotedStringInLocalPart in emailAddress.warnings
 60→        ) {
 61→            parserError(LocalPartRequiresQuotedString, position = 0)
 62→        }
 63→
 64→        if (!config.isEmptyLocalPartAllowed && Warning.EmptyLocalPart in emailAddress.warnings) {
 65→            parserError(EmptyLocalPart, position = 1)
 66→        }
 67→
 68→        return emailAddress
 69→    }
 70→
 71→    private fun readEmailAddress(): EmailAddress {
 72→        val localPart = readLocalPart()
 73→
 74→        expect(AT)
 75→        val domain = readDomainPart()
 76→
 77→        return EmailAddress(localPart, domain)
 78→    }
 79→
 80→    private fun readLocalPart(): String {
 81→        val character = peek()
 82→        val localPart = when {
 83→            character.isAtext -> {
 84→                readDotString()
 85→            }
 86→            character == DQUOTE -> {
 87→                if (config.isQuotedLocalPartAllowed) {
 88→                    readQuotedString()
 89→                } else {
 90→                    parserError(QuotedStringInLocalPart)
 91→                }
 92→            }
 93→            else -> {
 94→                parserError(InvalidLocalPart)
 95→            }
 96→        }
 97→
 98→        return localPart
 99→    }
100→
101→    private fun readDotString(): String {
102→        return buildString {
103→            appendAtom()
104→
105→            while (!endReached() && peek() == DOT) {
106→                expect(DOT)
107→                append(DOT)
108→                appendAtom()
109→            }
110→        }
111→    }
112→
113→    private fun StringBuilder.appendAtom() {
114→        val startIndex = currentIndex
115→        skipWhile { it.isAtext }
116→
117→        if (startIndex == currentIndex) {
118→            parserError(InvalidDotString)
119→        }
120→
121→        append(input, startIndex, currentIndex)
122→    }
123→
124→    private fun readQuotedString(): String {
125→        return buildString {
126→            expect(DQUOTE)
127→
128→            while (!endReached()) {
129→                val character = peek()
130→                when {
131→                    character.isQtext -> append(read())
132→                    character == BACKSLASH -> {
133→                        expect(BACKSLASH)
134→                        val escapedCharacter = read()
135→                        if (!escapedCharacter.isQuotedChar) {
136→                            parserError(InvalidQuotedString)
137→                        }
138→                        append(escapedCharacter)
139→                    }
140→
141→                    character == DQUOTE -> break
142→                    else -> parserError(InvalidQuotedString)
143→                }
144→            }
145→
146→            expect(DQUOTE)
147→        }
148→    }
149→
150→    private fun readDomainPart(): EmailDomain {
151→        val character = peek()
152→        return when {
153→            character.isLetDig -> readDomain()
154→            character == '[' -> parserError(AddressLiteralsNotSupported)
155→            else -> parserError(InvalidDomainPart)
156→        }
157→    }
158→
159→    private fun readDomain(): EmailDomain {
160→        return withParser(EmailDomainParser(input, currentIndex)) {
161→            readDomain()
162→        }
163→    }
164→}
